import React, { Component } from 'react';

class Test extends Component{
  render() {
    const { projects } = this.props;
    const projectList = projects.map(project => {
      return (
        <div className="project">
        <p>Name { project.name }</p>
        </div>
      )
    })
    return (
      <div className="project-list">
      { projectList }
      </div>
    )
  }
}

export default Test;
